import React, { useState, useEffect } from 'react';
import AsyncStorage from '@react-native/async-storage';

const LocalDataManager = () => {
  const [userData, setUserData] = useState(null);
  const [sessionData, setSessionData] = useState(null);
  const [offlineContent, setOfflineContent] = useState(null);

  useEffect(() => {
    getData();
  }, []);

  const getData = async () => {
    const userData = await AsyncStorage.getItem('userData');
    const sessionData = await AsyncStorage.getItem('sessionData');
    const offlineContent = await AsyncStorage.getItem('offlineContent');

    setUserData(JSON.parse(userData));
    setSessionData(JSON.parse(sessionData));
    setOfflineContent(JSON.parse(offlineContent));
  };

  const storeData = async (key, data) => {
    await AsyncStorage.setItem(key, JSON.stringify(data));
  };

  return {
    userData,
    sessionData,
    offlineContent,
    storeData,
  };
};

export default LocalDataManager;